import os
import secrets
import time
import hashlib
import hmac
import struct
import base64
from functools import wraps
from flask import Flask, request, jsonify, session, redirect, url_for, render_template_string

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# In-memory user store (replace with database in production)
users_db = {}
api_keys_db = {}
pending_mfa_sessions = {}

# --- TOTP Implementation ---

def generate_totp_secret():
    """Generate a random TOTP secret."""
    return base64.b32encode(secrets.token_bytes(20)).decode('utf-8')


def get_totp_token(secret, time_step=30, digits=6):
    """Generate a TOTP token for the current time."""
    key = base64.b32decode(secret, casefold=True)
    counter = int(time.time()) // time_step
    counter_bytes = struct.pack('>Q', counter)
    hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
    offset = hmac_hash[-1] & 0x0F
    truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
    token = truncated % (10 ** digits)
    return str(token).zfill(digits)


def verify_totp(secret, token, window=1, time_step=30):
    """Verify a TOTP token with a time window."""
    for i in range(-window, window + 1):
        key = base64.b32decode(secret, casefold=True)
        counter = (int(time.time()) // time_step) + i
        counter_bytes = struct.pack('>Q', counter)
        hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        offset = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
        expected = str(truncated % (10 ** 6)).zfill(6)
        if hmac.compare_digest(expected, token):
            return True
    return False


# --- Password Hashing ---

def hash_password(password, salt=None):
    """Hash a password with a salt."""
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return salt, hashed.hex()


def verify_password(password, salt, hashed):
    """Verify a password against its hash."""
    _, computed = hash_password(password, salt)
    return hmac.compare_digest(computed, hashed)


# --- Authentication Decorators ---

def login_required(f):
    """Decorator to require full authentication (including MFA if enabled)."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return jsonify({'error': 'Authentication required'}), 401
        if session.get('mfa_required') and not session.get('mfa_verified'):
            return jsonify({'error': 'MFA verification required'}), 403
        return f(*args, **kwargs)
    return decorated_function


def api_key_required(f):
    """Decorator to require valid API key authentication.
    
    API keys provide full authentication including implicit MFA bypass
    because API keys are long-lived secrets that represent pre-authorized
    machine-to-machine communication. The API key itself serves as the
    second factor (something you have).
    
    API keys should be:
    - Generated with sufficient entropy
    - Scoped to specific permissions
    - Rotated regularly
    - Transmitted only over HTTPS
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key:
            return jsonify({'error': 'API key required'}), 401

        api_key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        key_data = None
        for uid, data in api_keys_db.items():
            if hmac.compare_digest(data['key_hash'], api_key_hash):
                key_data = data
                break

        if key_data is None:
            return jsonify({'error': 'Invalid API key'}), 401

        if key_data.get('revoked', False):
            return jsonify({'error': 'API key has been revoked'}), 401

        request.api_user_id = key_data['user_id']
        request.api_key_scopes = key_data.get('scopes', [])
        return f(*args, **kwargs)
    return decorated_function


# --- User Management ---

@app.route('/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409

    salt, hashed = hash_password(password)
    users_db[username] = {
        'salt': salt,
        'password_hash': hashed,
        'mfa_enabled': False,
        'mfa_secret': None,
    }

    return jsonify({'message': 'User registered successfully'}), 201


# --- MFA Setup ---

@app.route('/setup-mfa', methods=['POST'])
@login_required
def setup_mfa():
    """Enable MFA for the current user. Returns the TOTP secret."""
    username = session.get('username')
    user = users_db.get(username)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user['mfa_enabled']:
        return jsonify({'error': 'MFA is already enabled'}), 400

    secret = generate_totp_secret()
    # Store secret temporarily; confirm with a valid token before enabling
    session['pending_mfa_secret'] = secret

    return jsonify({
        'message': 'Scan this secret with your authenticator app, then confirm with /confirm-mfa',
        'secret': secret,
        'provisioning_uri': f'otpauth://totp/MyApp:{username}?secret={secret}&issuer=MyApp'
    }), 200


@app.route('/confirm-mfa', methods=['POST'])
@login_required
def confirm_mfa():
    """Confirm MFA setup by verifying a token from the authenticator app."""
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({'error': 'OTP token required'}), 400

    username = session.get('username')
    user = users_db.get(username)
    pending_secret = session.get('pending_mfa_secret')

    if not pending_secret:
        return jsonify({'error': 'No pending MFA setup. Call /setup-mfa first.'}), 400

    token = data['token'].strip()
    if not token.isdigit() or len(token) != 6:
        return jsonify({'error': 'Token must be a 6-digit number'}), 400

    if verify_totp(pending_secret, token):
        user['mfa_enabled'] = True
        user['mfa_secret'] = pending_secret
        session.pop('pending_mfa_secret', None)
        return jsonify({'message': 'MFA enabled successfully'}), 200
    else:
        return jsonify({'error': 'Invalid token. MFA not enabled.'}), 400


@app.route('/disable-mfa', methods=['POST'])
@login_required
def disable_mfa():
    """Disable MFA for the current user. Requires current OTP for confirmation."""
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({'error': 'Current OTP token required to disable MFA'}), 400

    username = session.get('username')
    user = users_db.get(username)

    if not user or not user['mfa_enabled']:
        return jsonify({'error': 'MFA is not enabled'}), 400

    token = data['token'].strip()
    if verify_totp(user['mfa_secret'], token):
        user['mfa_enabled'] = False
        user['mfa_secret'] = None
        session['mfa_required'] = False
        session['mfa_verified'] = False
        return jsonify({'message': 'MFA disabled successfully'}), 200
    else:
        return jsonify({'error': 'Invalid OTP token'}), 400


# --- Web Login (with MFA support) ---

@app.route('/login', methods=['POST'])
def login():
    """
    Unified login endpoint.
    
    Step 1: Submit username + password.
    If MFA is not enabled -> fully authenticated.
    If MFA is enabled -> returns mfa_required, user must call /verify-mfa.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400

    user = users_db.get(username)
    if not user:
        # Constant-time-ish: still hash to avoid timing attacks
        hash_password(password)
        return jsonify({'error': 'Invalid credentials'}), 401

    if not verify_password(password, user['salt'], user['password_hash']):
        return jsonify({'error': 'Invalid credentials'}), 401

    # Password verified. Check MFA status.
    session['username'] = username
    session['authenticated'] = True

    if user['mfa_enabled']:
        # MFA is required - do NOT grant full access yet
        session['mfa_required'] = True
        session['mfa_verified'] = False
        return jsonify({
            'message': 'Password verified. MFA required.',
            'mfa_required': True
        }), 200
    else:
        # No MFA - fully authenticated
        session['mfa_required'] = False
        session['mfa_verified'] = False
        return jsonify({
            'message': 'Login successful',
            'mfa_required': False
        }), 200


@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    """
    Step 2 of login: Verify OTP token for users with MFA enabled.
    Only accessible after successful password verification.
    """
    if not session.get('authenticated'):
        return jsonify({'error': 'Password verification required first'}), 401

    if not session.get('mfa_required'):
        return jsonify({'error': 'MFA is not required for this account'}), 400

    if session.get('mfa_verified'):
        return jsonify({'message': 'MFA already verified'}), 200

    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({'error': 'OTP token required'}), 400

    username = session.get('username')
    user = users_db.get(username)

    if not user or not user['mfa_enabled']:
        return jsonify({'error': 'Invalid state'}), 400

    token = data['token'].strip()
    if not token.isdigit() or len(token) != 6:
        return jsonify({'error': 'Token must be a 6-digit number'}), 400

    if verify_totp(user['mfa_secret'], token):
        session['mfa_verified'] = True
        return jsonify({'message': 'MFA verified. Login complete.'}), 200
    else:
        return jsonify({'error': 'Invalid OTP token'}), 401


# --- API Key Authentication ---
# API keys are used for machine-to-machine communication.
# They are long-lived secrets that inherently bypass MFA because
# the API key itself serves as proof of authorization.

@app.route('/generate-api-key', methods=['POST'])
@login_required
def generate_api_key():
    """Generate an API key for the authenticated user.
    
    Requires full authentication (including MFA if enabled).
    This ensures that API key generation is protected by MFA.
    """
    username = session.get('username')
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json() or {}
    scopes = data.get('scopes', ['read'])

    # Generate a secure API key
    raw_key = secrets.token_urlsafe(48)
    key_hash = hashlib.sha256(raw_key.encode()).hexdigest()
    key_id = secrets.token_hex(8)

    api_keys_db[key_id] = {
        'user_id': username,
        'key_hash': key_hash,
        'scopes': scopes,
        'created_at': time.time(),
        'revoked': False,
    }

    return jsonify({
        'message': 'API key generated. Store it securely; it cannot be retrieved again.',
        'api_key': raw_key,
        'key_id': key_id,
        'scopes': scopes,
    }), 201


@app.route('/revoke-api-key', methods=['POST'])
@login_required
def revoke_api_key():
    """Revoke an API key."""
    data = request.get_json()
    if not data or 'key_id' not in data:
        return jsonify({'error': 'key_id required'}), 400

    key_id = data['key_id']
    username = session.get('username')

    if key_id not in api_keys_db:
        return jsonify({'error': 'API key not found'}), 404

    if api_keys_db[key_id]['user_id'] != username:
        return jsonify({'error': 'Not authorized to revoke this key'}), 403

    api_keys_db[key_id]['revoked'] = True
    return jsonify({'message': 'API key revoked'}), 200


